#include <stdio.h>
int main(){
    int t; if(scanf("%d", &t)!=1) return 0;
    while(t--){
        unsigned int n; scanf("%u", &n);
        if(n==0){
            printf("0\n");
            continue;
        }
        char buf[35]; // enough for 32‑bit numbers
        int idx = 0;
        while(n>0){
            buf[idx++] = (n % 2) + '0';
            n /= 2;
        }
        for(int i = idx-1; i >= 0; --i) putchar(buf[i]);
        putchar('\n');
    }
    return 0;
}

