    int t; if(!(cin>>t)) return 0;
    while(t--){
        unsigned int n; cin>>n;
        if(n==0){
            cout << "0\n";
            continue;
        }
        string bits;
        while(n>0){
            bits.push_back('0' + (n % 2));
            n /= 2;
        }
        reverse(bits.begin(), bits.end());
        cout << bits << '\n';
    }
    return 0;
}

