const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const t = Number(input[pos++]);
let results = [];
for(let i = 0; i < t; ++i){
    let n = Number(input[pos++]);
    if(n === 0){
        results.push('0');
        continue;
    }
    let bits = [];
    while(n > 0){
        bits.push((n % 2).toString());
        n = Math.floor(n / 2);
    }
    results.push(bits.reverse().join(''));
}
